// ═══════════════════════════════════════════════════════════════════════════
//  INTELLIGENCE FORMATTER
//  n8n Code Node  ·  Parse Groq response → Format for Telegram, Discord, Gmail
//  Stage : Post-LLM
//  Output: telegram_message | discord_body | gmail_html | routing metadata
// ═══════════════════════════════════════════════════════════════════════════


// ── 1.  Parse & sanitise raw LLM output ──────────────────────────────────────

const raw   = $input.first().json?.choices?.[0]?.message?.content ?? '{}';
const clean = raw.replace(/```json|```/g, '').trim();


// ── 2.  Constants ─────────────────────────────────────────────────────────────

/** Discord embed colour per threat tier (decimal RGB) */
const DISCORD_COLOR = {
  CRITICAL : 0xC0392B,   // deep red
  HIGH     : 0xE67E22,   // orange
  MODERATE : 0xF1C40F,   // amber
  LOW      : 0x27AE60    // green
};

/** Telegram lead emoji per threat tier */
const TIER_EMOJI = {
  CRITICAL : '🔴',
  HIGH     : '🟠',
  MODERATE : '🟡',
  LOW      : '🟢'
};

/** Gmail header palette per threat tier */
const GMAIL_PALETTE = {
  CRITICAL : { bg: '#fde8e8', border: '#c0392b', badge: '#c0392b', label: '🔴 CRITICAL' },
  HIGH     : { bg: '#fef0e7', border: '#e67e22', badge: '#e67e22', label: '🟠 HIGH'     },
  MODERATE : { bg: '#fef9e7', border: '#f1c40f', badge: '#b8860b', label: '🟡 MODERATE' },
  LOW      : { bg: '#eafaf1', border: '#27ae60', badge: '#27ae60', label: '🟢 LOW'      }
};

const IST_TIMESTAMP = new Date().toLocaleString('en-IN', {
  timeZone : 'Asia/Kolkata',
  day      : '2-digit', month: 'short', year: 'numeric',
  hour     : '2-digit', minute: '2-digit', hour12: true
});


// ── 3.  Schema normaliser (backward-compatible with old & new schema) ─────────
//
//  Old schema → new schema field mapping:
//    top_companies[]           → competitive_radar[]
//    strategic_recommendation  → strategic_playbook.immediate_action
//    executive_summary (str)   → executive_summary.situation + .implication

function normalise(p) {
  // ── Threat & score ──
  const threat = (
    p.threat_level ??
    p.briefing_metadata?.threat_level ??
    'LOW'
  ).toUpperCase().trim();

  const score = p.master_score ?? p.briefing_metadata?.master_score ?? 0;

  // ── Headline ──
  const headline = p.master_headline || 'No headline generated';

  // ── Executive summary — object (new) or string (old) ──
  const summaryRaw = p.executive_summary;
  const summary =
    summaryRaw && typeof summaryRaw === 'object'
      ? [summaryRaw.situation, summaryRaw.implication].filter(Boolean).join(' ')
      : String(summaryRaw ?? '');
  const urgency = summaryRaw?.urgency ?? '';

  // ── Companies — competitive_radar (new) or top_companies (old) ──
  const companies = (p.competitive_radar ?? p.top_companies ?? []).map(c => ({
    name     : c.company    ?? c.name    ?? 'Unknown',
    score    : c.intel_score ?? c.score  ?? 0,
    severity : c.severity   ?? '',
    signal   : c.detected_signal ?? c.status ?? '',
    counter  : c.counter_move ?? ''
  }));

  // ── Strategic playbook — object (new) or flat string (old) ──
  const playbook        = p.strategic_playbook ?? {};
  const immediateAction = playbook.immediate_action   ?? p.strategic_recommendation ?? '';
  const initiative30d   = playbook['30_day_initiative'] ?? '';
  const avoid           = playbook.do_not_do            ?? '';

  // ── Signal breakdown (new schema only) ──
  const signals = p.signal_breakdown ?? {};

  // ── Analyst note & watch list ──
  const analystNote = p.analyst_note ?? '';
  const watchNext   = Array.isArray(p.watch_next) ? p.watch_next : [];

  return {
    threat, score, headline,
    summary, urgency,
    companies, signals,
    immediateAction, initiative30d, avoid,
    analystNote, watchNext
  };
}


// ── 4.  Telegram formatter ────────────────────────────────────────────────────

function buildTelegram(d) {
  const emoji = TIER_EMOJI[d.threat] ?? '⚪';
  const lines = [];

  lines.push(
    `${emoji} *FINTECH COMPETITIVE INTEL*`,
    `━━━━━━━━━━━━━━━━━━━━━━━`,
    `*${d.headline}*`,
    ``,
    `🎯 Threat: *${d.threat}* · Score: *${d.score}/10*` +
      (d.urgency ? ` · Urgency: *${d.urgency}*` : ''),
    ``,
    `📋 *Executive Summary*`,
    d.summary || '_No summary available_'
  );

  if (d.companies.length > 0) {
    lines.push(``, `📡 *Competitive Radar*`);
    d.companies.forEach(c => {
      lines.push(
        `  • *${c.name}* [${c.score}/10]` +
          (c.severity ? ` — ${c.severity}` : ''),
        `    _${c.signal}_`
      );
    });
  }

  if (Object.keys(d.signals).length > 0) {
    lines.push(``, `📊 *Signal Breakdown*`);
    Object.entries(d.signals).forEach(([ch, s]) => {
      lines.push(`  ${ch.toUpperCase()}: ${s.key_signal ?? '—'} _(${s.score}/10)_`);
    });
  }

  if (d.immediateAction) {
    lines.push(``, `⚡ *Immediate Action*`, d.immediateAction);
  }
  if (d.initiative30d) {
    lines.push(``, `🗓 *30-Day Initiative*`, d.initiative30d);
  }
  if (d.avoid) {
    lines.push(``, `❌ *Avoid*`, d.avoid);
  }
  if (d.analystNote) {
    lines.push(``, `💡 *Analyst Note*`, `_${d.analystNote}_`);
  }
  if (d.watchNext.length > 0) {
    lines.push(``, `👀 *Watch Next*`);
    d.watchNext.forEach(w => lines.push(`  • ${w}`));
  }

  lines.push(
    ``,
    `━━━━━━━━━━━━━━━━━━━━━━━`,
    `_${IST_TIMESTAMP} IST · n8n Fintech Intel Bot_`
  );

  // Telegram hard limit: 4096 chars
  const msg = lines.join('\n');
  return msg.length > 4090
    ? msg.slice(0, 4080) + '…\n_[truncated]_'
    : msg;
}


// ── 5.  Discord formatter ─────────────────────────────────────────────────────
// Limits: description 4096, field value 1024, total embed 6000 chars

const cap = (str, n) => str.length > n ? str.slice(0, n - 1) + '…' : str;

function buildDiscord(d) {
  const color  = DISCORD_COLOR[d.threat] ?? DISCORD_COLOR.LOW;
  const fields = [];

  fields.push(
    { name: '🎯 Threat Level', value: `**${d.threat}**${d.urgency ? ` · ${d.urgency}` : ''}`, inline: true },
    { name: '📊 Master Score', value: `**${d.score}/10**`,                                       inline: true },
    { name: '\u200B',          value: '\u200B',                                                  inline: true }
  );

  if (d.immediateAction) {
    fields.push({ name: '⚡ Immediate Action', value: cap(d.immediateAction, 1024), inline: false });
  }

  if (d.companies.length > 0) {
    const radar = d.companies.map(c =>
      `**${c.name}** [${c.score}/10]${c.severity ? ` · ${c.severity}` : ''}\n${c.signal}`
    ).join('\n\n');
    fields.push({ name: '📡 Competitive Radar', value: cap(radar, 1024), inline: false });
  }

  if (Object.keys(d.signals).length > 0) {
    const breakdown = Object.entries(d.signals).map(([ch, s]) =>
      `**${ch.toUpperCase()}** (${s.score}/10): ${s.key_signal ?? '—'}`
    ).join('\n');
    fields.push({ name: '📊 Signal Breakdown', value: cap(breakdown, 1024), inline: false });
  }

  if (d.initiative30d) {
    fields.push({ name: '🗓 30-Day Initiative', value: cap(d.initiative30d, 1024), inline: false });
  }

  if (d.avoid) {
    fields.push({ name: '❌ Do Not Do', value: cap(d.avoid, 1024), inline: false });
  }

  if (d.watchNext.length > 0) {
    fields.push({
      name   : '👀 Watch Next',
      value  : cap(d.watchNext.map(w => `• ${w}`).join('\n'), 1024),
      inline : false
    });
  }

  if (d.analystNote) {
    fields.push({ name: '💡 Analyst Note', value: cap(`*${d.analystNote}*`, 1024), inline: false });
  }

  return JSON.stringify({
    username : 'Fintech Intel Bot',
    embeds   : [{
      title      : cap(d.headline, 256),
      color,
      description: cap(d.summary, 4096),
      fields,
      footer     : { text: `n8n Fintech Intel Bot · ${IST_TIMESTAMP} IST` }
    }]
  });
}


// ── 6.  Gmail HTML formatter ──────────────────────────────────────────────────
// All styles are inline — Gmail strips <style> blocks in some contexts

function buildGmail(d) {
  const p = GMAIL_PALETTE[d.threat] ?? GMAIL_PALETTE.LOW;

  // ── Competitive radar table rows ──
  const hasCounter   = d.companies.some(c => c.counter);
  const compRows     = d.companies.map(c => `
    <tr>
      <td style="padding:10px 14px;border-bottom:1px solid #f0f0f0;font-weight:600;color:#1a1a2e;white-space:nowrap">${c.name}</td>
      <td style="padding:10px 14px;border-bottom:1px solid #f0f0f0;text-align:center">
        <span style="background:#eff2ff;color:#2c3e8c;padding:2px 8px;border-radius:12px;font-size:12px;font-weight:700">${c.score}/10</span>
      </td>
      ${c.severity ? `<td style="padding:10px 14px;border-bottom:1px solid #f0f0f0;font-size:12px;color:#666;white-space:nowrap">${c.severity}</td>` : '<td style="padding:10px 14px;border-bottom:1px solid #f0f0f0"></td>'}
      <td style="padding:10px 14px;border-bottom:1px solid #f0f0f0;font-size:13px;color:#333;line-height:1.5">${c.signal}</td>
      ${hasCounter ? `<td style="padding:10px 14px;border-bottom:1px solid #f0f0f0;font-size:12px;color:#1e6b3a;line-height:1.5">${c.counter}</td>` : ''}
    </tr>`).join('');

  // ── Signal breakdown table rows ──
  const signalRows = Object.entries(d.signals).map(([ch, s]) => `
    <tr>
      <td style="padding:8px 14px;border-bottom:1px solid #f5f5f5">
        <span style="font-weight:700;text-transform:uppercase;font-size:11px;color:#888;letter-spacing:0.5px">${ch}</span>
      </td>
      <td style="padding:8px 14px;border-bottom:1px solid #f5f5f5;font-size:13px;color:#333">${s.key_signal ?? '—'}</td>
      <td style="padding:8px 14px;border-bottom:1px solid #f5f5f5;text-align:center;white-space:nowrap">
        <span style="background:#eff2ff;color:#2c3e8c;padding:2px 6px;border-radius:10px;font-size:11px;font-weight:700">${s.score}/10</span>
      </td>
      <td style="padding:8px 14px;border-bottom:1px solid #f5f5f5;font-size:12px;color:#999;font-style:italic">${s.what_to_ignore ?? ''}</td>
    </tr>`).join('');

  // ── Watch next list ──
  const watchItems = d.watchNext.map(w =>
    `<li style="margin-bottom:6px;color:#444;font-size:14px;line-height:1.6">${w}</li>`
  ).join('');

  // ── Playbook cards (3 possible: immediate / 30-day / avoid) ──
  const playbookCards = [
    d.immediateAction ? `
      <div style="background:#eff2ff;border-left:3px solid #2c3e8c;padding:14px 18px;border-radius:0 8px 8px 0;margin-bottom:10px">
        <div style="font-size:10px;font-weight:700;color:#2c3e8c;letter-spacing:1px;margin-bottom:6px">⚡ IMMEDIATE ACTION</div>
        <div style="font-size:14px;color:#1a1a2e;line-height:1.6">${d.immediateAction}</div>
      </div>` : '',
    d.initiative30d ? `
      <div style="background:#eafaf1;border-left:3px solid #27ae60;padding:14px 18px;border-radius:0 8px 8px 0;margin-bottom:10px">
        <div style="font-size:10px;font-weight:700;color:#1e8449;letter-spacing:1px;margin-bottom:6px">🗓 30-DAY INITIATIVE</div>
        <div style="font-size:14px;color:#1a1a2e;line-height:1.6">${d.initiative30d}</div>
      </div>` : '',
    d.avoid ? `
      <div style="background:#fff5f5;border-left:3px solid #c0392b;padding:14px 18px;border-radius:0 8px 8px 0">
        <div style="font-size:10px;font-weight:700;color:#922b21;letter-spacing:1px;margin-bottom:6px">❌ DO NOT DO</div>
        <div style="font-size:14px;color:#1a1a2e;line-height:1.6">${d.avoid}</div>
      </div>` : ''
  ].filter(Boolean).join('');

  return `<!DOCTYPE html>
<html>
<body style="margin:0;padding:0;background:#f4f6fb;font-family:'Segoe UI',Arial,sans-serif">
<div style="max-width:700px;margin:32px auto;background:#ffffff;border-radius:12px;overflow:hidden;box-shadow:0 2px 16px rgba(0,0,0,0.09)">

  <!-- ── Header ── -->
  <table width="100%" cellpadding="0" cellspacing="0" style="background:#1a1a2e">
    <tr>
      <td style="padding:28px 32px">
        <div style="font-size:10px;letter-spacing:2.5px;color:#6b7fa8;font-weight:600;margin-bottom:10px">CONFIDENTIAL · FINTECH INTELLIGENCE BRIEFING</div>
        <div style="font-size:20px;font-weight:700;color:#ffffff;line-height:1.4">${d.headline}</div>
      </td>
    </tr>
  </table>

  <!-- ── Threat badge ── -->
  <table width="100%" cellpadding="0" cellspacing="0" style="background:${p.bg};border-left:4px solid ${p.border}">
    <tr>
      <td style="padding:14px 32px">
        <span style="background:${p.badge};color:#ffffff;padding:4px 14px;border-radius:20px;font-size:11px;font-weight:700;letter-spacing:0.5px">${p.label}</span>
        <span style="color:${p.badge};font-size:13px;font-weight:600;margin-left:16px">
          Score: ${d.score}/10${d.urgency ? `&nbsp;&nbsp;·&nbsp;&nbsp;${d.urgency}` : ''}
        </span>
      </td>
    </tr>
  </table>

